// Lookup sprite by piece value (positive=white, negative=black)
// Piece types: 1=Pawn, 2=Knight, 3=Bishop, 4=Rook, 5=Queen, 6=King
inline const uint8_t* getChessPieceSprite(int8_t piece) {
  if (piece == 0) return nullptr;
  static constexpr const uint8_t* WHITE_PIECES[] = {
    nullptr,         // 0: empty
    CHESS_W_PAWN,    // 1: pawn
    CHESS_W_KNIGHT,  // 2: knight
    CHESS_W_BISHOP,  // 3: bishop
    CHESS_W_ROOK,    // 4: rook
    CHESS_W_QUEEN,   // 5: queen
    CHESS_W_KING,    // 6: king
  };
  static constexpr const uint8_t* BLACK_PIECES[] = {
    nullptr,         // 0: empty
    CHESS_B_PAWN,    // 1: pawn
    CHESS_B_KNIGHT,  // 2: knight
    CHESS_B_BISHOP,  // 3: bishop
    CHESS_B_ROOK,    // 4: rook
    CHESS_B_QUEEN,   // 5: queen
    CHESS_B_KING,    // 6: king
  };
  int8_t type = piece > 0 ? piece : -piece;
  if (type < 1 || type > 6) return nullptr;
  return piece > 0 ? WHITE_PIECES[type] : BLACK_PIECES[type];
}
